export interface Addendum {
  id: string;
  body: string;
  author: string;
  at: string; // ISO datetime
}

export interface SoapNote {
  id: string;
  /** Reverse-chronological key. */
  at: string; // 記録日時 ISO datetime
  author: string; // recording nurse
  problemRef: number | null; // linked 看護問題 # (focus charting)
  s: string;
  o: string;
  a: string;
  p: string;
  /** "signed" = sealed, append-only legal record. "draft" = editable. */
  status: "draft" | "signed";
  signedBy: string | null;
  signedAt: string | null; // ISO datetime
  addenda: Addendum[];
}

export interface NursingProblem {
  id: number; // # number
  label: string; // 看護診断
  relatedFactors: string; // 関連因子
  goal: string; // 看護目標
  evaluation: Evaluation;
  resolved: boolean;
  raisedOn: string; // ISO date
}

export interface CareItem {
  id: string;
  label: string;
  schedule: string; // e.g. "2時間毎", "10:00 / 14:00 / 18:00"
  problemRef: number | null;
  status: CareStatus;
  doneAt: string | null; // ISO datetime when toggled done
