} from "./data";

const NURSE = patient.nurse;

/* ── small presentational helpers ─────────────────────────────── */

function HeaderFact({
  icon: Icon,
  label,
  children,
}: {
  icon: TablerIcon;
  label: string;
  children: React.ReactNode;
}) {
  return (
    <div className="flex items-start gap-2">
      <Icon className="mt-0.5 h-4 w-4 shrink-0 text-muted-foreground" aria-hidden />
      <div className="min-w-0">
        <div className="text-xs text-muted-foreground">{label}</div>
        <div className="truncate text-sm font-medium text-foreground">{children}</div>
      </div>
    </div>
  );
}

const SOAP_FIELDS: { key: "s" | "o" | "a" | "p"; letter: string; label: string; hint: string }[] = [
  { key: "s", letter: "S", label: "主観的情報", hint: "患者・家族の訴え、言葉" },
  { key: "o", letter: "O", label: "客観的情報", hint: "観察・測定・所見" },
  { key: "a", letter: "A", label: "アセスメント", hint: "情報の解釈・判断" },
  { key: "p", letter: "P", label: "計画", hint: "今後の看護計画・対応" },
];

function evaluationTone(e: Evaluation): "success" | "warning" | "info" {
  if (e === "達成") return "success";
  if (e === "未達成") return "warning";
  return "info";
}

/* ── SOAP read-back block (used inside signed note cards) ──────── */

function SoapReadout({ note }: { note: SoapNote }) {
  return (
    <dl className="mt-3 grid gap-2 sm:grid-cols-2">
      {SOAP_FIELDS.map((f) => (
        <div key={f.key} className="rounded-md border border-border bg-muted/30 p-3">
          <dt className="flex items-center gap-2 text-xs font-semibold text-muted-foreground">
            <span className="inline-flex h-5 w-5 items-center justify-center rounded bg-foreground text-[11px] font-bold text-background">
              {f.letter}
            </span>
            {f.label}
          </dt>
          <dd className="mt-1.5 whitespace-pre-wrap break-words text-sm text-foreground">
            {note[f.key] || <span className="text-muted-foreground">（記載なし）</span>}
          </dd>
        </div>
      ))}
    </dl>
  );
}

/* ── one note in the reverse-chronological timeline ───────────── */

function NoteCard({
  note,
  problems,
  onSign,
  onAddAddendum,
}: {
  note: SoapNote;
  problems: NursingProblem[];
  onSign: (id: string) => void;
  onAddAddendum: (id: string, body: string) => void;
}) {
  const signed = note.status === "signed";
  const linkedProblem = problems.find((p) => p.id === note.problemRef);
  const [addOpen, setAddOpen] = React.useState(false);
  const [addText, setAddText] = React.useState("");

  const submitAddendum = () => {
    if (!addText.trim()) return;
    onAddAddendum(note.id, addText.trim());
    setAddText("");
    setAddOpen(false);
  };

  return (
    <Card
      className={signed ? "border-success-border/60" : "border-warning-border/60"}
      aria-readonly={signed || undefined}
    >
      <CardHeader className="gap-2 p-4 sm:p-5">
        <div className="flex flex-wrap items-center justify-between gap-2">
          <div className="flex items-center gap-2">
            <TimelineHeading note={note} />
          </div>
          {signed ? (
            <Badge variant="success" className="gap-1">
              <IconLock className="h-3 w-3" aria-hidden />
              署名済 ・ 記録確定
            </Badge>
          ) : (
            <Badge variant="warning" className="gap-1">
              <IconLockOpen className="h-3 w-3" aria-hidden />
              下書き ・ 未署名
            </Badge>
          )}
        </div>
        <div className="flex flex-wrap items-center gap-x-3 gap-y-1 text-xs text-muted-foreground">
          <span className="inline-flex items-center gap-1">
            <IconUser className="h-3.5 w-3.5" aria-hidden />
            記録者 {note.author}
          </span>
          {linkedProblem ? (
            <Badge variant="outline" className="font-normal">
              #{linkedProblem.id} {linkedProblem.label}
            </Badge>
          ) : null}
        </div>
      </CardHeader>

      <CardContent className="p-4 pt-0 sm:p-5 sm:pt-0">
        <SoapReadout note={note} />

        {/* 署名・追記の監査証跡 (audit trail) */}
        {signed ? (
          <div className="mt-3 rounded-md border border-success-border/50 bg-success-subtle/40 px-3 py-2 text-xs text-success-subtle-foreground">
            <span className="inline-flex items-center gap-1 font-semibold">
              <IconSignature className="h-3.5 w-3.5" aria-hidden />
              {note.signedBy} が署名
            </span>
            <span className="ml-1">
              （{note.signedAt ? formatDateTime(note.signedAt) : "—"}）
            </span>
            <span className="ml-1">この記録は確定済みのため編集できません。修正は追記で行います。</span>
          </div>
        ) : null}

        {/* 追記チェーン (addendum chain) */}
        {note.addenda.length > 0 ? (
          <ul className="mt-3 space-y-2 border-l-2 border-info-border/60 pl-3">
            {note.addenda.map((ad: Addendum, i: number) => (
              <li key={ad.id} className="text-sm">
                <div className="flex flex-wrap items-center gap-2 text-xs text-muted-foreground">
                  <Badge variant="info" className="gap-1">
                    <IconCornerDownRight className="h-3 w-3" aria-hidden />
                    追記 {i + 1}
                  </Badge>
                  <span>{formatDateTime(ad.at)}</span>
                  <span>・ {ad.author}</span>
                </div>
                <p className="mt-1 whitespace-pre-wrap break-words text-foreground">{ad.body}</p>
              </li>
            ))}
          </ul>
        ) : null}
      </CardContent>

      <CardFooter className="flex-wrap gap-2 p-4 pt-0 sm:p-5 sm:pt-0">
        {signed ? (
          <Dialog open={addOpen} onOpenChange={setAddOpen}>
            <Button variant="outline" size="sm" onClick={() => setAddOpen(true)}>
              <IconPlus className="h-4 w-4" aria-hidden />
              追記を追加
            </Button>
            <DialogContent>
              <DialogHeader>
                <DialogTitle>追記 (Addendum)</DialogTitle>
                <DialogDescription>
                  確定済みの記録は変更できません。追記は独自のタイムスタンプ・記録者として記録の末尾に追加されます。
                </DialogDescription>
              </DialogHeader>
              <div className="space-y-3">
                <Alert variant="info">
                  <IconLock className="h-4 w-4" aria-hidden />
                  <AlertTitle as="p">元の記録（{formatDateTime(note.at)}）は保持されます</AlertTitle>
                  <AlertDescription>
                    記録者 {NURSE} ・ {formatDateTime(nowLocalInput())} として追記します。
                  </AlertDescription>
                </Alert>
                <FormField>
                  <FormLabel>追記内容</FormLabel>
                  <FormControl>
                    <Textarea
                      value={addText}
                      onChange={(e) => setAddText(e.target.value)}
                      rows={4}
                      placeholder="経過の補足・修正内容を記載"
                    />
                  </FormControl>
                </FormField>
              </div>
              <DialogFooter>
                <Button variant="outline" onClick={() => setAddOpen(false)}>
                  キャンセル
                </Button>
                <Button onClick={submitAddendum} disabled={!addText.trim()}>
                  <IconCornerDownRight className="h-4 w-4" aria-hidden />
                  追記を保存
                </Button>
              </DialogFooter>
            </DialogContent>
          </Dialog>
        ) : (
          <>
            <Badge variant="warning" className="gap-1">
              <IconAlertTriangle className="h-3 w-3" aria-hidden />
              署名すると編集不可になります
            </Badge>
            <Button variant="success" size="sm" onClick={() => onSign(note.id)} className="ml-auto">
              <IconSignature className="h-4 w-4" aria-hidden />
              署名して確定
            </Button>
          </>
        )}
      </CardFooter>
    </Card>
  );
}

function TimelineHeading({ note }: { note: SoapNote }) {
  return (
    <div>
      <TimelineTitle className="text-base">経過記録</TimelineTitle>
      <TimelineTime dateTime={note.at}>{formatDateTime(note.at)}</TimelineTime>
    </div>
