}

/* ── SOAP composer (note-in-composition state) ────────────────── */

const EMPTY_SOAP = { s: "", o: "", a: "", p: "" };

function SoapComposer({
  problems,
  onSaveDraft,
}: {
  problems: NursingProblem[];
  onSaveDraft: (note: Omit<SoapNote, "id" | "status" | "signedBy" | "signedAt" | "addenda">) => void;
}) {
  const [fields, setFields] = React.useState(EMPTY_SOAP);
  const [recordedAt, setRecordedAt] = React.useState(nowLocalInput());
  const [problemRef, setProblemRef] = React.useState<string>("");
  const [attempted, setAttempted] = React.useState(false);

  const hasContent =
    fields.s.trim() || fields.o.trim() || fields.a.trim() || fields.p.trim();
  const charCount =
    fields.s.length + fields.o.length + fields.a.length + fields.p.length;

  const set = (key: "s" | "o" | "a" | "p", v: string) =>
    setFields((f) => ({ ...f, [key]: v }));

  const reset = () => {
    setFields(EMPTY_SOAP);
    setRecordedAt(nowLocalInput());
    setProblemRef("");
    setAttempted(false);
  };

  const handleSave = () => {
    setAttempted(true);
    if (!hasContent) return;
    onSaveDraft({
      at: recordedAt,
      author: NURSE,
      problemRef: problemRef ? Number(problemRef) : null,
      ...fields,
    });
    reset();
  };

  return (
    <Card>
      <CardHeader className="p-4 sm:p-5">
        <div className="flex items-center gap-2">
          <IconWriting className="h-5 w-5 text-foreground" aria-hidden />
          <CardTitle as="h3" className="text-lg">
            新規 SOAP 記録
          </CardTitle>
        </div>
        <CardDescription>
          S/O/A/P を記載し下書き保存します。署名するまで何度でも編集できます。
        </CardDescription>
      </CardHeader>
      <CardContent className="space-y-4 p-4 pt-0 sm:p-5 sm:pt-0">
        <div className="grid gap-4 sm:grid-cols-2">
          <FormField>
            <FormLabel>記録日時</FormLabel>
            <FormControl>
              <Input
                type="datetime-local"
                value={recordedAt}
                onChange={(e) => setRecordedAt(e.target.value)}
              />
            </FormControl>
          </FormField>
          <FormField>
            <FormLabel>関連する看護問題（任意）</FormLabel>
            <FormControl>
              <Select
                value={problemRef}
                onChange={(e) => setProblemRef(e.target.value)}
                aria-label="関連する看護問題"
              >
                <option value="">紐付けなし</option>
                {problems
                  .filter((p) => !p.resolved)
                  .map((p) => (
                    <option key={p.id} value={String(p.id)}>
                      #{p.id} {p.label}
                    </option>
                  ))}
              </Select>
            </FormControl>
          </FormField>
        </div>

        <div className="grid gap-4 sm:grid-cols-2">
          {SOAP_FIELDS.map((f) => (
            <FormField key={f.key}>
              <FormLabel>
                <span className="inline-flex items-center gap-2">
                  <span className="inline-flex h-5 w-5 items-center justify-center rounded bg-foreground text-[11px] font-bold text-background">
                    {f.letter}
                  </span>
                  {f.label}
                </span>
              </FormLabel>
              <FormControl>
                <Textarea
                  value={fields[f.key]}
                  onChange={(e) => set(f.key, e.target.value)}
                  rows={4}
                  placeholder={f.hint}
                />
              </FormControl>
              <FormDescription>{f.hint}</FormDescription>
            </FormField>
          ))}
        </div>

        {attempted && !hasContent ? (
          <Alert variant="warning">
            <IconAlertTriangle className="h-4 w-4" aria-hidden />
            <AlertTitle as="p">記録内容が空です</AlertTitle>
            <AlertDescription>
              S/O/A/P のいずれかに記載してから保存してください。
            </AlertDescription>
          </Alert>
        ) : null}
      </CardContent>
      <CardFooter className="flex-wrap gap-2 p-4 pt-0 sm:p-5 sm:pt-0">
        <span className="text-xs text-muted-foreground" aria-live="polite">
          {charCount} 文字 ・ 記録者 {NURSE}
        </span>
        <div className="ml-auto flex flex-wrap gap-2">
          <Button variant="outline" onClick={reset} disabled={!hasContent}>
            クリア
          </Button>
          <Button onClick={handleSave} disabled={!hasContent}>
            <IconNotes className="h-4 w-4" aria-hidden />
            下書き保存
          </Button>
        </div>
      </CardFooter>
    </Card>
  );
}

/* ── 看護問題 / 看護診断 list ──────────────────────────────────── */

function ProblemList({
  problems,
  onEvaluate,
  onToggleResolved,
}: {
  problems: NursingProblem[];
  onEvaluate: (id: number, e: Evaluation) => void;
  onToggleResolved: (id: number) => void;
}) {
  const active = problems.filter((p) => !p.resolved);
  const resolved = problems.filter((p) => p.resolved);

  return (
    <div className="space-y-4">
      <div className="flex items-center justify-between">
        <p className="text-sm text-muted-foreground">
          活動中の問題 <span className="font-semibold text-foreground">{active.length}</span> 件
        </p>
      </div>

      <ul className="space-y-3">
        {problems.map((p) => (
          <li key={p.id}>
            <Card className={p.resolved ? "opacity-70" : undefined}>
              <CardContent className="space-y-3 p-4">
                <div className="flex flex-wrap items-start justify-between gap-2">
                  <div className="flex items-start gap-2">
                    <Badge variant={p.resolved ? "secondary" : "default"}>#{p.id}</Badge>
                    <div>
                      <h3 className="text-base font-semibold text-foreground">
                        {p.label}
                        {p.resolved ? (
                          <span className="ml-2 text-xs font-normal text-muted-foreground">
                            （解決済み）
                          </span>
                        ) : null}
                      </h3>
                      <p className="text-xs text-muted-foreground">
                        {p.relatedFactors} ・ 立案 {formatDate(p.raisedOn)}
                      </p>
                    </div>
                  </div>
                  {!p.resolved ? (
                    <Badge variant={evaluationTone(p.evaluation)}>{p.evaluation}</Badge>
                  ) : (
                    <Badge variant="success" className="gap-1">
                      <IconCircleCheck className="h-3 w-3" aria-hidden />
                      解決
                    </Badge>
                  )}
                </div>

                <div className="rounded-md border border-border bg-muted/30 p-3 text-sm">
                  <span className="text-xs font-semibold text-muted-foreground">看護目標</span>
                  <p className="mt-0.5 text-foreground">{p.goal}</p>
                </div>

                {!p.resolved ? (
                  <div className="flex flex-wrap items-end justify-between gap-3">
                    <div className="w-full max-w-[200px]">
                      <Select
                        label="評価"
                        value={p.evaluation}
                        onChange={(e) => onEvaluate(p.id, e.target.value as Evaluation)}
                      >
                        <option value="継続">継続</option>
                        <option value="達成">達成</option>
                        <option value="未達成">未達成</option>
                      </Select>
                    </div>
                    <Button variant="outline" size="sm" onClick={() => onToggleResolved(p.id)}>
                      <IconCircleCheck className="h-4 w-4" aria-hidden />
                      解決にする
                    </Button>
                  </div>
                ) : (
                  <Button variant="ghost" size="sm" onClick={() => onToggleResolved(p.id)}>
                    再度活動中に戻す
                  </Button>
                )}
              </CardContent>
            </Card>
          </li>
        ))}
      </ul>

      {resolved.length > 0 ? (
        <p className="text-xs text-muted-foreground">解決済み {resolved.length} 件を含む</p>
      ) : null}
    </div>
  );
}

/* ── 看護計画 / ケア schedule ──────────────────────────────────── */

function CarePlan({
  items,
  onToggle,
}: {
  items: CareItem[];
  onToggle: (id: string) => void;
}) {
  const done = items.filter((i) => i.status === "done").length;
  return (
    <div className="space-y-4">
      <Alert variant="info">
        <IconChecklist className="h-4 w-4" aria-hidden />
        <AlertTitle as="p">本勤務のケア実施状況</AlertTitle>
        <AlertDescription>
          {items.length} 件中 {done} 件実施済み。実施するとチェックと実施時刻が記録されます。
        </AlertDescription>
      </Alert>

      <ul className="space-y-2">
        {items.map((item) => {
          const isDone = item.status === "done";
          return (
            <li key={item.id}>
              <Card>
                <CardContent className="flex flex-wrap items-center gap-3 p-3 sm:p-4">
                  <Checkbox
                    checked={isDone}
                    onCheckedChange={() => onToggle(item.id)}
                    aria-label={`${item.label} を実施済みにする`}
                  />
                  <div className="min-w-0 flex-1">
                    <div className="flex flex-wrap items-center gap-2">
                      <span
                        className={
                          isDone
                            ? "text-sm font-medium text-muted-foreground line-through"
                            : "text-sm font-medium text-foreground"
                        }
                      >
                        {item.label}
                      </span>
                      <Badge variant="outline" className="font-normal">
                        {item.category}
                      </Badge>
                    </div>
                    <p className="text-xs text-muted-foreground">
                      <IconClockHour4 className="mr-1 inline h-3 w-3" aria-hidden />
                      {item.schedule}
                      {item.doneAt ? ` ・ 実施 ${formatDateTime(item.doneAt)}` : ""}
                    </p>
                  </div>
                  {isDone ? (
                    <Badge variant="success" className="gap-1">
                      <IconCircleCheck className="h-3 w-3" aria-hidden />
                      実施済
                    </Badge>
                  ) : (
                    <Badge variant="warning">未実施</Badge>
                  )}
                </CardContent>
              </Card>
            </li>
          );
        })}
      </ul>
    </div>
  );
}

/* ── 申し送り (handoff / SBAR) ─────────────────────────────────── */

const SBAR_FIELDS: { key: "s" | "b" | "a" | "r"; letter: string; label: string; hint: string }[] =
  [
    { key: "s", letter: "S", label: "状況 (Situation)", hint: "現在の状態・主訴" },
    { key: "b", letter: "B", label: "背景 (Background)", hint: "経過・関連する情報" },
    { key: "a", letter: "A", label: "評価 (Assessment)", hint: "看護師の判断" },
    { key: "r", letter: "R", label: "提案・依頼 (Recommendation)", hint: "次勤務への観察点・依頼" },
  ];

function Handoff() {
  const [open, setOpen] = React.useState(false);
  const [sbar, setSbar] = React.useState({
    s: "右大腿骨頸部骨折 術後5日目。疼痛コントロール良好（NRS 2-3）、本日歩行器歩行を見守りで開始。",
    b: "高齢・術後の下肢筋力低下あり。夜間に単独でトイレへ行こうとし離床センサー作動の既往。",
    a: "転倒リスク高。疼痛は夜間に増強傾向。創部感染徴候なし。",
    r: "夜間排泄はNCを再徹底。夜間NRS4以上で頓用使用を検討。ポータブルトイレ設置を申し送る。",
  });
  const [saved, setSaved] = React.useState(true);

  const set = (key: "s" | "b" | "a" | "r", v: string) => {
    setSbar((p) => ({ ...p, [key]: v }));
    setSaved(false);
  };

  return (
    <div className="space-y-4">
      <Alert variant="info">
        <IconArrowsTransferUp className="h-4 w-4" aria-hidden />
        <AlertTitle as="p">次勤務への申し送り（SBAR）</AlertTitle>
        <AlertDescription>
          現在の状態と観察点を SBAR 形式で簡潔にまとめます。確定すると申し送り記録として保存されます。
        </AlertDescription>
      </Alert>

      <Card>
        <CardContent className="space-y-4 p-4 sm:p-5">
          <div className="grid gap-4 sm:grid-cols-2">
            {SBAR_FIELDS.map((f) => (
              <FormField key={f.key}>
                <FormLabel>
                  <span className="inline-flex items-center gap-2">
                    <span className="inline-flex h-5 w-5 items-center justify-center rounded bg-info-strong text-[11px] font-bold text-info-strong-foreground">
                      {f.letter}
                    </span>
                    {f.label}
                  </span>
                </FormLabel>
                <FormControl>
                  <Textarea
                    value={sbar[f.key]}
                    onChange={(e) => set(f.key, e.target.value)}
                    rows={3}
                    placeholder={f.hint}
                  />
                </FormControl>
              </FormField>
            ))}
          </div>
        </CardContent>
        <CardFooter className="flex-wrap gap-2 p-4 pt-0 sm:p-5 sm:pt-0">
          <span className="text-xs text-muted-foreground" aria-live="polite">
            {saved ? "保存済み" : "未保存の変更があります"}
          </span>
          <Dialog open={open} onOpenChange={setOpen}>
            <Button className="ml-auto" onClick={() => setOpen(true)}>
              <IconArrowsTransferUp className="h-4 w-4" aria-hidden />
              申し送りを確定
            </Button>
            <DialogContent>
              <DialogHeader>
                <DialogTitle>申し送りの確定</DialogTitle>
                <DialogDescription>
                  {NURSE} ・ {formatDateTime(nowLocalInput())} の申し送りとして保存します。
                </DialogDescription>
              </DialogHeader>
              <dl className="space-y-2 text-sm">
                {SBAR_FIELDS.map((f) => (
                  <div key={f.key} className="rounded-md border border-border bg-muted/30 p-2">
                    <dt className="text-xs font-semibold text-muted-foreground">{f.label}</dt>
                    <dd className="mt-0.5 whitespace-pre-wrap text-foreground">{sbar[f.key]}</dd>
                  </div>
                ))}
              </dl>
              <DialogFooter>
                <Button variant="outline" onClick={() => setOpen(false)}>
                  戻る
                </Button>
                <Button
                  variant="success"
                  onClick={() => {
                    setSaved(true);
                    setOpen(false);
                  }}
                >
                  <IconCircleCheck className="h-4 w-4" aria-hidden />
                  確定して保存
                </Button>
              </DialogFooter>
            </DialogContent>
          </Dialog>
        </CardFooter>
      </Card>
    </div>
  );
}

/* ── page root ────────────────────────────────────────────────── */

export default function NursingRecord() {
  const [notes, setNotes] = React.useState<SoapNote[]>(initialNotes);
  const [problems, setProblems] = React.useState<NursingProblem[]>(initialProblems);
  const [careItems, setCareItems] = React.useState<CareItem[]>(initialCareItems);

  // reverse-chronological (newest first)
  const orderedNotes = React.useMemo(
    () => [...notes].sort((a, b) => (a.at < b.at ? 1 : -1)),
    [notes],
  );
  const draftCount = notes.filter((n) => n.status === "draft").length;
  const activeProblemCount = problems.filter((p) => !p.resolved).length;
  const pendingCareCount = careItems.filter((c) => c.status === "pending").length;

  const handleSaveDraft = (
    base: Omit<SoapNote, "id" | "status" | "signedBy" | "signedAt" | "addenda">,
  ) => {
    setNotes((prev) => [
      {
        ...base,
        id: `n${Date.now()}`,
        status: "draft",
        signedBy: null,
        signedAt: null,
        addenda: [],
      },
      ...prev,
    ]);
  };

  const handleSign = (id: string) => {
    setNotes((prev) =>
      prev.map((n) =>
        n.id === id && n.status === "draft"
          ? { ...n, status: "signed", signedBy: NURSE, signedAt: nowLocalInput() }
          : n,
      ),
    );
  };

  const handleAddAddendum = (id: string, body: string) => {
    setNotes((prev) =>
      prev.map((n) =>
        n.id === id && n.status === "signed"
          ? {
              ...n,
              addenda: [
                ...n.addenda,
                { id: `a${Date.now()}`, body, author: NURSE, at: nowLocalInput() },
              ],
            }
          : n,
      ),
    );
  };

  const handleEvaluate = (id: number, e: Evaluation) =>
    setProblems((prev) => prev.map((p) => (p.id === id ? { ...p, evaluation: e } : p)));

  const handleToggleResolved = (id: number) =>
    setProblems((prev) =>
      prev.map((p) =>
        p.id === id
          ? { ...p, resolved: !p.resolved, evaluation: !p.resolved ? "達成" : p.evaluation }
          : p,
      ),
    );

  const handleToggleCare = (id: string) =>
    setCareItems((prev) =>
      prev.map((c) =>
        c.id === id
          ? c.status === "done"
            ? { ...c, status: "pending", doneAt: null }
            : { ...c, status: "done", doneAt: nowLocalInput() }
          : c,
      ),
    );

  return (
    <main className="mx-auto w-full max-w-5xl px-4 py-6 sm:px-6 sm:py-8">
      <header className="mb-6">
        <div className="flex flex-wrap items-center gap-2">
          <IconStethoscope className="h-6 w-6 text-foreground" aria-hidden />
          <h1 className="text-2xl font-bold tracking-tight text-foreground sm:text-3xl">
            看護記録 / 経過記録
          </h1>
        </div>
        <p className="mt-1 text-sm text-muted-foreground">
          SOAP 形式で経過を記録し、署名により法的記録として確定します。署名済みの記録は編集できず、追記のみ可能です。
        </p>
      </header>

      {/* 患者コンテキスト */}
      <Card className="mb-6">
        <CardContent className="p-4 sm:p-5">
          <div className="flex flex-wrap items-center justify-between gap-3">
            <div className="flex items-center gap-3">
              <span className="flex h-11 w-11 items-center justify-center rounded-full bg-muted">
                <IconUser className="h-6 w-6 text-muted-foreground" aria-hidden />
              </span>
              <div>
                <div className="flex items-center gap-2">
                  <h2 className="text-lg font-semibold text-foreground">{patient.name}</h2>
                  <Badge variant="outline" className="font-normal">
                    {patient.kana}
                  </Badge>
                </div>
                <p className="text-sm text-muted-foreground">
                  {patient.age}歳 ・ {patient.sex}性 ・ ID {patient.id}
                </p>
              </div>
            </div>
            <Badge variant="info" className="gap-1">
              <IconCalendarEvent className="h-3 w-3" aria-hidden />
              入院 {formatDate(patient.admittedOn)} ・ 病日 {patient.hospitalDay}日目
            </Badge>
          </div>

          <Separator className="my-4" />

          <div className="grid grid-cols-1 gap-4 sm:grid-cols-2 lg:grid-cols-3">
            <HeaderFact icon={IconBedFilled} label="病棟 / 病室">
              {patient.ward} ・ {patient.room}号 {patient.bed}床
            </HeaderFact>
            <HeaderFact icon={IconUser} label="担当看護師">
              {patient.nurse}
            </HeaderFact>
            <HeaderFact icon={IconStethoscope} label="主病名">
              {patient.diagnosis}
            </HeaderFact>
          </div>
        </CardContent>
      </Card>

      <Tabs defaultValue="notes">
        <TabsList className="flex w-full flex-wrap">
          <TabsTrigger value="notes" className="gap-1.5">
            <IconNotes className="h-4 w-4" aria-hidden />
            経過記録
            {draftCount > 0 ? (
              <Badge variant="warning" className="ml-1">
                下書き {draftCount}
              </Badge>
            ) : null}
          </TabsTrigger>
          <TabsTrigger value="problems" className="gap-1.5">
            <IconClipboardList className="h-4 w-4" aria-hidden />
            看護問題
            <Badge variant="secondary" className="ml-1">
              {activeProblemCount}
            </Badge>
          </TabsTrigger>
          <TabsTrigger value="care" className="gap-1.5">
            <IconChecklist className="h-4 w-4" aria-hidden />
            看護計画
            {pendingCareCount > 0 ? (
              <Badge variant="secondary" className="ml-1">
                未 {pendingCareCount}
              </Badge>
            ) : null}
          </TabsTrigger>
          <TabsTrigger value="handoff" className="gap-1.5">
            <IconArrowsTransferUp className="h-4 w-4" aria-hidden />
            申し送り
          </TabsTrigger>
        </TabsList>

        {/* ── 経過記録 ── */}
        <TabsContent value="notes" className="space-y-6 px-0">
          <SoapComposer problems={problems} onSaveDraft={handleSaveDraft} />

          <section aria-label="経過記録一覧">
            <div className="mb-3 flex items-center justify-between">
              <h2 className="text-lg font-semibold text-foreground">経過記録（新しい順）</h2>
              <span className="text-xs text-muted-foreground">{notes.length} 件</span>
            </div>
            <Timeline>
              {orderedNotes.map((note, i) => (
                <TimelineItem
                  key={note.id}
                  variant={note.status === "signed" ? "success" : "warning"}
                  connector={i < orderedNotes.length - 1}
                >
                  <NoteCard
                    note={note}
                    problems={problems}
                    onSign={handleSign}
                    onAddAddendum={handleAddAddendum}
                  />
                </TimelineItem>
              ))}
            </Timeline>
          </section>
        </TabsContent>

        {/* ── 看護問題 ── */}
        <TabsContent value="problems" className="px-0">
          <h2 className="sr-only">看護問題 / 看護診断リスト</h2>
          <ProblemList
            problems={problems}
            onEvaluate={handleEvaluate}
            onToggleResolved={handleToggleResolved}
          />
        </TabsContent>

        {/* ── 看護計画 ── */}
        <TabsContent value="care" className="px-0">
          <h2 className="sr-only">看護計画 / ケアスケジュール</h2>
          <CarePlan items={careItems} onToggle={handleToggleCare} />
        </TabsContent>

        {/* ── 申し送り ── */}
        <TabsContent value="handoff" className="px-0">
          <h2 className="sr-only">申し送り</h2>
          <Handoff />
        </TabsContent>
      </Tabs>
    </main>
  );
}
